@dataclass
class Address:
    street: str
    city: str
    state: str
    zip_code: str
    country: str


@dataclass
class UserData:
    user_id: str
    email: str
    phone_number: str
    first_name: str
    last_name: str
    address: Address
    date_of_birth: Optional[str] = None
    ssn: Optional[str] = None
    
    def to_dict(self) -> Dict[str, Any]:
        data = asdict(self)
        if isinstance(data.get('address'), dict):
            return data
        return data


class SQSPublisher:
    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None
    ):
        self.queue_url = queue_url
        
        if aws_access_key_id and aws_secret_access_key:
            self.sqs_client = boto3.client(
                'sqs',
                region_name=region_name,
                aws_access_key_id=aws_access_key_id,
                aws_secret_access_key=aws_secret_access_key
            )
        else:
            self.sqs_client = boto3.client('sqs', region_name=region_name)
    
    def publish_user_data(
        self,
        user_data: UserData,
        message_group_id: Optional[str] = None,
        deduplication_id: Optional[str] = None
    ) -> Dict[str, Any]:
        message_body = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'data_type': 'user_pii',
            'user_data': user_data.to_dict()
        }
        
        try:
            kwargs = {
                'QueueUrl': self.queue_url,
                'MessageBody': json.dumps(message_body)
            }
            
            if message_group_id:
                kwargs['MessageGroupId'] = message_group_id
            
            if deduplication_id:
                kwargs['MessageDeduplicationId'] = deduplication_id
            
            response = self.sqs_client.send_message(**kwargs)
            
            return {
                'success': True,
                'message_id': response['MessageId'],
                'sequence_number': response.get('SequenceNumber'),
                'response_metadata': response['ResponseMetadata']
            }
            
        except ClientError as e:
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }
    
    def publish_batch_user_data(
        self,
        user_data_list: List[UserData],
        message_group_id: Optional[str] = None
    ) -> Dict[str, Any]:
        if len(user_data_list) > 10:
            raise ValueError("Maximum batch size is 10 messages")
        
        entries = []
        for idx, user_data in enumerate(user_data_list):
            message_body = {
                'message_id': str(uuid.uuid4()),
                'timestamp': datetime.utcnow().isoformat(),
                'data_type': 'user_pii',
                'user_data': user_data.to_dict()
            }
            
            entry = {
                'Id': str(idx),
                'MessageBody': json.dumps(message_body)
            }
            
            if message_group_id:
                entry['MessageGroupId'] = message_group_id
                entry['MessageDeduplicationId'] = f"{user_data.user_id}-{uuid.uuid4()}"
            
            entries.append(entry)
        
        try:
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url,
                Entries=entries
            )
            
            return {
                'success': True,
                'successful': response.get('Successful', []),
                'failed': response.get('Failed', []),
                'response_metadata': response['ResponseMetadata']
            }
            
        except ClientError as e:
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }
    
    def publish_with_attributes(
        self,
        user_data: UserData,
        attributes: Dict[str, Any],
        message_group_id: Optional[str] = None
    ) -> Dict[str, Any]:
        message_body = {
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'data_type': 'user_pii',
            'user_data': user_data.to_dict()
        }
        
        message_attributes = {}
        for key, value in attributes.items():
            if isinstance(value, str):
                message_attributes[key] = {
                    'StringValue': value,
                    'DataType': 'String'
                }
            elif isinstance(value, (int, float)):
                message_attributes[key] = {
                    'StringValue': str(value),
                    'DataType': 'Number'
                }
        
        try:
            kwargs = {
                'QueueUrl': self.queue_url,
                'MessageBody': json.dumps(message_body),
                'MessageAttributes': message_attributes
            }
            
            if message_group_id:
                kwargs['MessageGroupId'] = message_group_id
                kwargs['MessageDeduplicationId'] = f"{user_data.user_id}-{uuid.uuid4()}"
            
            response = self.sqs_client.send_message(**kwargs)
            
            return {
                'success': True,
                'message_id': response['MessageId'],
                'sequence_number': response.get('SequenceNumber'),
                'response_metadata': response['ResponseMetadata']
            }
            
        except ClientError as e:
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }
    
    def get_queue_attributes(self) -> Dict[str, Any]:
        try:
            response = self.sqs_client.get_queue_attributes(
                QueueUrl=self.queue_url,
                AttributeNames=['All']
            )
            return {
                'success': True,
                'attributes': response['Attributes']
            }
        except ClientError as e:
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }


class PIIDataPublisher:
    def __init__(self, sqs_publisher: SQSPublisher):
        self.publisher = sqs_publisher
    
    def publish_user_registration(
        self,
        email: str,
        phone_number: str,
        first_name: str,
        last_name: str,
        street: str,
        city: str,
        state: str,
        zip_code: str,
        country: str = 'USA',
        date_of_birth: Optional[str] = None,
        ssn: Optional[str] = None
    ) -> Dict[str, Any]:
        user_id = str(uuid.uuid4())
        
        address = Address(
            street=street,
            city=city,
            state=state,
            zip_code=zip_code,
            country=country
        )
        
        user_data = UserData(
            user_id=user_id,
            email=email,
            phone_number=phone_number,
            first_name=first_name,
            last_name=last_name,
            address=address,
            date_of_birth=date_of_birth,
            ssn=ssn
        )
        
        attributes = {
            'event_type': 'user_registration',
            'data_classification': 'PII',
            'requires_encryption': 'true'
        }
        
        return self.publisher.publish_with_attributes(
            user_data=user_data,
            attributes=attributes
        )
    
    def publish_user_profile_update(
        self,
        user_id: str,
        email: Optional[str] = None,
        phone_number: Optional[str] = None,
        address: Optional[Dict[str, str]] = None
    ) -> Dict[str, Any]:
        update_data = {
            'user_id': user_id,
            'message_id': str(uuid.uuid4()),
            'timestamp': datetime.utcnow().isoformat(),
            'event_type': 'profile_update',
            'updates': {}
        }
        
        if email:
            update_data['updates']['email'] = email
        if phone_number:
            update_data['updates']['phone_number'] = phone_number
        if address:
            update_data['updates']['address'] = address
        
        try:
            response = self.publisher.sqs_client.send_message(
                QueueUrl=self.publisher.queue_url,
                MessageBody=json.dumps(update_data),
                MessageAttributes={
                    'event_type': {
                        'StringValue': 'profile_update',
                        'DataType': 'String'
                    },
                    'data_classification': {
                        'StringValue': 'PII',
                        'DataType': 'String'
                    }
                }
            )
            
            return {
                'success': True,
                'message_id': response['MessageId']
            }
            
        except ClientError as e:
            return {
                'success': False,
                'error': str(e),
                'error_code': e.response['Error']['Code']
            }
    
    def publish_bulk_user_data(
        self,
        users: List[Dict[str, Any]]
    ) -> Dict[str, Any]:
        user_data_list = []
        
        for user in users:
            address = Address(
                street=user['address']['street'],
                city=user['address']['city'],
                state=user['address']['state'],
                zip_code=user['address']['zip_code'],
                country=user['address'].get('country', 'USA')
            )
            
            user_data = UserData(
                user_id=user.get('user_id', str(uuid.uuid4())),
                email=user['email'],
                phone_number=user['phone_number'],
                first_name=user['first_name'],
                last_name=user['last_name'],
                address=address,
                date_of_birth=user.get('date_of_birth'),
                ssn=user.get('ssn')
            )
            
            user_data_list.append(user_data)
        
        results = []
        for i in range(0, len(user_data_list), 10):
            batch = user_data_list[i:i+10]
            result = self.publisher.publish_batch_user_data(batch)
            results.append(result)
        
        return {
            'batch_results': results,
            'total_processed': len(user_data_list)
        }


